const tunnels = $input.first().json.tunnels ?? [];
const tunnel = tunnels.find(t => t.proto === 'https') ?? tunnels[0];
if (!tunnel) {
  throw new Error('Heartbeat: no ngrok tunnel found. Is the ngrok sidecar running?');
}
const url = tunnel.public_url;
console.log('[Heartbeat] Detected ngrok URL:', url);
return [{ json: { url } }];

const data = $input.first().json;
const workflows = data.data ?? [];
const RECEPTIONIST_NAMES = [
  '[UNIFIED] Multi-Channel Router',
  'YAOC2 Telegram Receptionist',
  'YAOC2 WhatsApp Receptionist'
];
const targets = workflows.filter(w =>
  RECEPTIONIST_NAMES.some(name => w.name?.includes(name) || name.includes(w.name))
);
if (targets.length === 0) {
  console.log('[Heartbeat] No receptionist workflows found on brain. Skipping bounce.');
  return [{ json: { bounce_ids: [], skipped: true } }];
}
console.log('[Heartbeat] Bouncing:', targets.map(w => w.name + ' (' + w.id + ')').join(', '));
return [{ json: { bounce_ids: targets.map(w => w.id), skipped: false } }];

const brainUrl = $env.BRAIN_N8N_URL ?? 'http://192.168.101.168:5678';
const apiKey = $env.BRAIN_N8N_API_KEY;
if (!apiKey) throw new Error('Heartbeat: BRAIN_N8N_API_KEY not set');
const ids = $input.first().json.bounce_ids ?? [];
const results = [];
for (const id of ids) {
  try {
    await $helpers.httpRequest({
      method: 'PATCH',
      url: `${brainUrl}/api/v1/workflows/${id}`,
      headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
      body: JSON.stringify({ active: false })
    });
    await new Promise(r => setTimeout(r, 800));
    await $helpers.httpRequest({
      method: 'PATCH',
      url: `${brainUrl}/api/v1/workflows/${id}`,
      headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
      body: JSON.stringify({ active: true })
    });
    results.push({ id, bounced: true });
    console.log('[Heartbeat] Bounced workflow:', id);
  } catch(e) {
    results.push({ id, bounced: false, error: e.message });
    console.warn('[Heartbeat] Failed to bounce workflow ' + id + ':', e.message);
  }
}
return [{ json: { bounce_results: results, completed_at: new Date().toISOString() } }];
